    },
    {
      "name": "rolling_52w_start_cte",
      "purpose": "Determine the inclusive start of the 52-week rolling window.",
      "logic": "Compute window_start_date = (max_week_end_date - 51 weeks) to include exactly 52 weeks ending on max_week_end_date."
    }
  ],
  "group_by": [
    "week_end_date"
  ],
  "order_by": [
    {
      "column": "week_end_date",
      "direction": "ASC"
    }
  ],
  "limit": null,
  "final_output": {
    "columns": [
      "week_end_date",
      "weekly_sales"
    ],
    "row_granularity": "per_group"
  },
  "validation_rules": [
    "Use data_867 as the anchor table for sales.",
    "Use week_end_date for weekly calculations and windowing.",
    "Derive the rolling window relative to MAX(week_end_date) in the data; do not use system date.",
    "The 52-week window must be inclusive: week_end_date between (max_week_end_date - 51 weeks) and max_week_end_date.",
    "Default to national sales; do not group by campus_id, campus_account_name, or parent-level columns.",
    "Use relmora_total_mg (not relmora_total_sls) because market share/competitor comparison was not requested.",
    "Return one row per week_end_date present in the data; do not attempt to generate or fill missing weeks.",
    "weekly_sales must be an integer (SUM of INT relmora_total_mg)."
  ],
  "rag_alignment": {
    "rag_provided": true,
    "used_examples": [
      "Example #1"
    ],
    "borrowed_patterns": [
      "rolling 52-week window anchored to MAX(week_end_date)",
      "filter week_end_date between derived window start and derived max_date",
      "group by week_end_date and order ascending",
      "single weekly SUM metric output with week_end_date"
    ],
    "differences_from_examples": [
      "Used data_867 table and SUM(relmora_total_mg) instead of the example's drug_sales and qty_sold_pu, per schema and relmora-only metric rules.",
      "Metric name is weekly_sales per required naming rule for weekly granularity."
    ]
  }
}
